$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$TASK_ISSUE = "41"

# Poll for PR using all three strategies
$timeout = 900
$interval = 30
$elapsed = 0
$prNumber = $null

while ($elapsed -lt $timeout) {
    # Strategy A: issue timeline for cross-referenced PRs
    $prNumber = gh api "/repos/$REPO/issues/$TASK_ISSUE/timeline" --jq '.[] | select(.event == "cross-referenced") | select(.source.issue.pull_request != null) | select(.source.issue.state == "open") | .source.issue.number' 2>$null | Select-Object -First 1

    if (-not $prNumber) {
        # Strategy B: PR body search
        $prNumber = gh pr list -R $REPO --state open --json number,body --jq ".[] | select(.body | test(`"#$TASK_ISSUE`")) | .number" 2>$null | Select-Object -First 1
    }

    if (-not $prNumber) {
        # Strategy C: title/branch match
        $prNumber = gh pr list -R $REPO --state open --json number,title,headRefName --jq ".[] | select((.title | test(`"$TASK_ISSUE`"; `"i`")) or (.headRefName | test(`"$TASK_ISSUE`"))) | .number" 2>$null | Select-Object -First 1
    }

    if ($prNumber) {
        Write-Host "Found PR #$prNumber after ${elapsed}s"
        break
    }

    Write-Host "Polling... ${elapsed}s elapsed, no PR yet"
    Start-Sleep -Seconds $interval
    $elapsed += $interval
}

if (-not $prNumber) {
    Write-Host "TIMEOUT: No PR found after ${timeout}s"
} else {
    Write-Host "PR_NUMBER=$prNumber"
    # Verify base branch
    $actualBase = gh pr view $prNumber -R $REPO --json baseRefName --jq '.baseRefName'
    Write-Host "Base branch: $actualBase"
}

