$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR_NUMBER = "42"
$branch = "copilot/edburns28-python-agent-demo"

# Poll for checks to appear or action_required runs
$timeout = 600
$interval = 30
$elapsed = 0

while ($elapsed -lt $timeout) {
    # Check for action_required runs
    $actionRequired = gh run list -R $REPO --branch $branch --status action_required --json databaseId,name 2>$null | ConvertFrom-Json
    if ($actionRequired -and $actionRequired.Count -gt 0) {
        Write-Host "Found action_required runs after ${elapsed}s:"
        $actionRequired | ForEach-Object { Write-Host "  Run $($_.databaseId): $($_.name)" }
        break
    }

    # Check if checks have appeared
    $checks = gh pr checks $PR_NUMBER -R $REPO 2>&1
    if ($LASTEXITCODE -eq 0) {
        Write-Host "Checks appeared after ${elapsed}s:"
        Write-Host $checks
        break
    }

    # Check for completed runs
    $completedRuns = gh run list -R $REPO --branch $branch --json databaseId,name,status,conclusion 2>$null | ConvertFrom-Json
    if ($completedRuns -and $completedRuns.Count -gt 0) {
        Write-Host "Found runs after ${elapsed}s:"
        $completedRuns | ForEach-Object { Write-Host "  Run $($_.databaseId): $($_.name) - $($_.status)/$($_.conclusion)" }
        break
    }

    Write-Host "Waiting... ${elapsed}s elapsed"
    Start-Sleep -Seconds $interval
    $elapsed += $interval
}

if ($elapsed -ge $timeout) {
    Write-Host "Timeout waiting for checks/runs"
}

