$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR_NUMBER = "42"
$branch = "copilot/edburns28-python-agent-demo"

# Wait for Copilot agent run to complete and CI checks to appear
$timeout = 600
$interval = 30
$elapsed = 0

while ($elapsed -lt $timeout) {
    Start-Sleep -Seconds $interval
    $elapsed += $interval

    # Check if the copilot agent run is done
    $runs = gh run list -R $REPO --branch $branch --json databaseId,name,status,conclusion 2>$null | ConvertFrom-Json
    $agentRun = $runs | Where-Object { $_.name -like "*Copilot*" }
    $otherRuns = $runs | Where-Object { $_.name -notlike "*Copilot*" }

    Write-Host "${elapsed}s - Agent: $($agentRun.status)/$($agentRun.conclusion) | Other runs: $($otherRuns.Count)"

    if ($otherRuns -and $otherRuns.Count -gt 0) {
        Write-Host "CI runs found:"
        $otherRuns | ForEach-Object { Write-Host "  $($_.databaseId): $($_.name) - $($_.status)/$($_.conclusion)" }
        break
    }

    # Also check for action_required
    $actionRequired = gh run list -R $REPO --branch $branch --status action_required --json databaseId,name 2>$null | ConvertFrom-Json
    if ($actionRequired -and $actionRequired.Count -gt 0) {
        Write-Host "Action required runs found:"
        $actionRequired | ForEach-Object { Write-Host "  $($_.databaseId): $($_.name)" }
        break
    }
}

if ($elapsed -ge $timeout) {
    Write-Host "Timeout - checking final state"
    gh run list -R $REPO --branch $branch --json databaseId,name,status,conclusion
}

